+func TestTotalLoadMatchesNodeLoadsForWithinBoundAssignments(t *testing.T) {
+	h := NewBoundedLoadHash(3, 1.25)
+	nodes := []string{"node-a"}
+	addNodes(h, nodes)
+
+	for i := 0; i < 8; i++ {
+		if node := h.Get(fmt.Sprintf("within-bound-key-%d", i)); node == "" {
+			t.Fatalf("Get returned no node")
+		}
+		assertTotalLoadMatchesSum(t, h, nodes)
+	}
+}
+
+func TestTotalLoadMatchesNodeLoadsAfterAssignmentsReleasesAndRemove(t *testing.T) {
+	h := NewBoundedLoadHash(3, 1.25)
+	nodes := []string{"node-a", "node-b", "node-c"}
+	addNodes(h, nodes)
+
+	assignments := make([]string, 0, 6)
+	for i := 0; i < 6; i++ {
+		node := h.Get(fmt.Sprintf("mixed-key-%d", i))
+		if node == "" {
+			t.Fatalf("Get returned no node")
+		}
+		assignments = append(assignments, node)
+		assertTotalLoadMatchesSum(t, h, nodes)
+	}
+
+	h.Release(assignments[0])
+	assertTotalLoadMatchesSum(t, h, nodes)
+
+	h.Release(assignments[2])
+	assertTotalLoadMatchesSum(t, h, nodes)
+
+	removedNode := assignments[1]
+	h.Remove(removedNode)
+	nodes = withoutNode(nodes, removedNode)
+	assertTotalLoadMatchesSum(t, h, nodes)
+
+	if node := h.Get("mixed-key-after-remove"); node == "" {
+		t.Fatalf("Get returned no node after remove")
+	}
+	assertTotalLoadMatchesSum(t, h, nodes)
+}
+
+func TestTotalLoadMatchesNodeLoadsAcrossBoundBoundary(t *testing.T) {
+	h := NewBoundedLoadHash(1, 1.0)
+	nodes := []string{"node-a", "node-b"}
+	addNodes(h, nodes)
+
+	for i := 0; i < len(nodes); i++ {
+		if node := h.Get(fmt.Sprintf("boundary-key-%d", i)); node == "" {
+			t.Fatalf("Get returned no node")
+		}
+		assertTotalLoadMatchesSum(t, h, nodes)
+	}
+
+	for _, node := range nodes {
+		if load := h.Load(node); load != 1 {
+			t.Fatalf("load for %s = %d, want 1 before over-bound assignment", node, load)
+		}
+	}
+	if maxLoad := h.maxLoadPerNode(); maxLoad != 1 {
+		t.Fatalf("max load before over-bound assignment = %d, want 1", maxLoad)
+	}
+
+	if node := h.Get("boundary-key-over-bound"); node == "" {
+		t.Fatalf("Get returned no node")
+	}
+	assertTotalLoadMatchesSum(t, h, nodes)
+
+	loads := []int{h.Load(nodes[0]), h.Load(nodes[1])}
+	if !((loads[0] == 2 && loads[1] == 1) || (loads[0] == 1 && loads[1] == 2)) {
+		t.Fatalf("loads after over-bound assignment = %v, want one node at 2 and one at 1", loads)
+	}
+}
+
+func addNodes(h *BoundedLoadHash, nodes []string) {
+	for _, node := range nodes {
+		h.Add(node)
+	}
+}
